INSERT INTO courses (course_id, title, description, category) VALUES
('3f88f62e-7669-595c-a9aa-3c013397b933', 'Single Variable Calculus', 'Covers single-variable differentiation and integration, concluding with an introduction to infinite series. [Source: MIT OpenCourseWare, 18.01SC Single Variable Calculus, Fall 2010. Instructors: David Jerison et al. License: CC BY-NC-SA. https://ocw.mit.edu]', 'Calculus');
INSERT INTO chapters (chapter_id, course_id, title, description, xp_reward, order_index) VALUES
('b5e47c2b-127c-5487-b420-d80ebe26ff73', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Unit 1A: Definition and Basic Rules', 'This section explains what differentiation is and gives rules for differentiating familiar functions. » Session 1: Introduction to Derivatives » Session 2: Examples of Derivatives » Session 3: Derivative as Rate of Change » Session 4: Limits and Continuity » Session 5: Discontinuity » Session 6: Calculating Derivatives » Session 7: Derivatives of Sine and Cosine » Session 8: Limits of Sine and Cosine » Session 9: Product Rule » Session 10: Quotient Rule » Session 11: Chain Rule » Session 12: Higher Derivatives » Problem Set 1', 100, 1),
('4fb7ac97-3a6e-534e-8d12-fb8dd35a5309', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Unit 1B: Implicit Differentiation and Inverse Functions', 'This section extends the methods of Part A to exponential and implicitly defined functions. By the end of Part B, we are able to differentiate most elementary functions. » Session 13: Implicit Differentiation » Session 14: Examples of Implicit Differentiation » Session 15: Implicit Differentiation and Inverse Functions » Session 16: The Derivative of a » Session 17: The Exponential Function, its Derivative, and its Inverse » Session 18: Derivatives of other Exponential Functions » Session 19: An Interesting Limit Involving e » Session 20: Hyperbolic Trig Functions » Problem Set 2', 100, 2),
('1c3ce2ce-cd05-549e-80b7-1f5b07f2eac8', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Unit 1 - Exam 1', 'Congratulations! You’ve made it through Unit 1. Now it’s time to test your knowledge. Begin with the review, and when you’re ready, take the exam. When you’re done, use the included solutions to check your answers. » Session 21: Review for Exam 1 - Computing Derivatives Using Differentiation Rules » Session 22: Materials for Exam 1', 100, 3),
('0ac62e43-dc95-5e3d-9441-d865f02b9073', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Unit 2A: Approximation and Curve Sketching', 'This section describes how differentiation can be used to simplify complex calculations and graph functions. » Session 23: Linear Approximation » Session 24: Examples of Linear Approximation » Session 25: Introduction to Quadratic Approximation » Session 26: Using Quadratic Approximations » Session 27: Sketching Graphs I - Polynomials and Rational Functions » Session 28: Sketching Graphs II - General Strategies » Problem Set 3', 100, 4),
('31681478-3717-562e-b63d-6e43894e7975', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Unit 2B: Optimization, Related Rates and Newton''s Method', 'The study of the greatest and least outputs of a function – highest profits, least materials used, closest approach – is called optimization. In addition to optimization, this part of the course also describes how to use derivatives to relate two rates of change and to estimate the values for which a function’s output is zero. » Session 29: Optimization Problems » Session 30: Optimization Problems II » Session 31: Related Rates » Session 32: Ring on a String » Session 33: Newton’s Method » Problem Set 4', 100, 5),
('7a70454d-e8b6-594c-8876-f2b470867989', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Unit 2C: Mean Value Theorem, Antiderivatives and Differential Equations', 'The Mean Value Theorem is the key to proving that our abstract definition of a “derivative” faithfully describes our informal notion of a “rate of change.” The second half of this part of the course introduces notation for and discusses the possibility of reversing the process of differentiation. » Session 34: Introduction to the Mean Value Theorem » Session 35: Using the Mean Value Theorem » Session 36: Differentials » Session 37: Antiderivatives » Session 38: Integration by Substitution » Session 39: Introduction to Differential Equations » Session 40: Separation of Variables » Problem Set 5', 100, 6),
('8bd6a4b8-b147-5510-abc7-99516cddaed3', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Unit 2 - Exam 2', 'Congratulations! You’ve made it through Unit 2. Now it’s time to test your knowledge. Begin with the review, and when you’re ready, take the exam. When you’re done, use the included solutions to check your answers. » Session 41: Review for Exam 2 » Session 42: Materials for Exam 2', 100, 7),
('1b2b0cf8-5bdb-5ee1-a053-0874ed9b37ed', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Unit 3A: Definition of the Definite Integral and First Fundamental Theorem', 'The definite integral of a function describes the area between the graph of that function and the horizontal axis. The First Fundamental Theorem of Calculus confirms that we can use what we learned about derivatives to quickly calculate this area. » Session 43: Definite Integrals » Session 44: Adding Areas of Rectangles » Session 45: Some Easy Integrals » Session 46: Riemann Sums » Session 47: Introduction of the Fundamental Theorem of Calculus » Session 48: The Fundamental Theorem of Calculus » Session 49: Applications of the Fundamental Theorem of Calculus » Session 50: Combining the Fundamental Theorem and the Mean Value Theorem » Problem Set 6', 100, 8),
('fe6367a0-7280-589f-9150-b5847a2c35ed', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Unit 3B: Second Fundamental Theorem, Areas, Volumes', 'The Second Fundamental Theorem of Calculus describes how integration is the opposite of differentiation. It allows us to understand functions defined in terms of definite integrals, some of which are impossible to describe using more elementary methods. This part of the course also covers the use of integration to calculate volumes of solids. » Session 51: The Second Fundamental Theorem of Calculus » Session 52: Proving the Fundamental Theorem of Calculus » Session 53: New Functions From Old » Session 54: The Second Fundamental Theorem and ln(x) » Session 55: Creating New Functions Using the Second Fundamental Theorem » Session 56: Geometric Interpretation of Definite Integrals » Session 57: How to Calculate Volumes » Session 58: Volume of a Sphere, Revolving About x-axis » Session 59: Volume of a Parabaloid, Revolving About y-axis » Problem Set 7', 100, 9),
('c6a83b42-9c8b-5abb-af3e-6eb335698d63', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Unit 3C: Average Value, Probability and Numerical Integration', 'Calculating averages and probabilities is an important application of integration. Although we can differentiate almost any function we can describe, there are functions whose integral we cannot directly describe; this part of the course describes numerical methods used to calculate the values of such integrals. » Session 60: Integrals and Averages » Session 61: Integrals and Weighted Averages » Session 62: Integrals and Probability » Session 63: Numerical Integration » Session 64: Numerical Integration, Continued » Session 65: Bell Curve, Conclusion » Problem Set 8', 100, 10),
('2603c58b-6883-571e-b229-9ada39dcb6ae', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Unit 3 - Exam 3', 'Congratulations! You’ve made it through Unit 3. Now it’s time to test your knowledge. Begin with the review, and when you’re ready, take the exam. When you’re done, use the included solutions to check your answers. » Session 66: Review for Exam 3 » Session 67: Materials for Exam 3', 100, 11),
('d5c5ce0f-f9ac-5567-8ab4-b4c2e528bb5b', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Unit 4A: Trigonometric Powers,  Trigonometric Substitution and Completing the Square', 'This part of the course describes how to integrate trigonometric functions, and how to use trigonometric functions to calculate otherwise intractable integrals. » Session 68: Integral of sinⁿ(x) cosᵐ(x), Odd Exponents » Session 69: Integral of sinⁿ(x) cosᵐ(x), Even Exponents » Session 70: Preview of Trig Substitution and Polar Coordinates » Session 71: Integrals Involving secant, cosecant and cotangent » Session 72: Trig Substitution » Session 73: Completing the Square » Problem Set 9', 100, 12),
('d7840e6c-c206-5c15-b53c-158ea62408f5', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Unit 4B: Partial Fractions, Integration by Parts, Arc Length, and Surface Area', 'Partial Fractions Decomposition and Integration by Parts are techniques for simplifying complex integrals. In this part of the course we also describe how to use integration to find the length of a portion of a graph and the surface area of a rotationally symmetric surface. » Session 74: Integration by Partial Fractions » Session 75: Advanced Partial Fractions » Session 76: Integration by Parts » Session 77: Volume of a Wine Glass » Session 78: Computing the Length of a Curve » Session 79: Surface Area » Problem Set 10', 100, 13),
('92251838-98a2-55cc-bcbb-577d71b3a494', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Unit 4C: Parametric Equations and Polar Coordinates', 'We start by extending our technique for finding the length of a portion of a graph to cover any curve we can describe algebraically. The remainder of this part of the course explores Polar Coordinates, an alternative method of describing locations in the plane. » Session 80: Parametric Curves » Session 81: Examples Using Parametrized Curves » Session 82: Polar Coordinates » Session 83: Polar Coordinates, Continued » Session 84: Polar Coordinates and Graphing » Problem Set 11', 100, 14),
('466b2ebb-4193-565a-ae65-4f79caf1ac5d', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Unit 4 - Exam 4', 'Congratulations! You’ve made it through Unit 4. Now it’s time to test your knowledge. Begin with the review, and when you’re ready, take the exam. When you’re done, use the included solutions to check your answers. » Session 85: Review for Exam 4 » Session 86: Materials for Exam 4', 100, 15),
('730bb547-5e1e-5a51-bcab-ae8c04a72483', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Unit 5A: L''Hospital''s Rule and Improper Integrals', 'L’Hospital’s rule describes how we can use the derivative to calculate certain limits. The second half of this part of the course discusses how to calculate the area under a graph when that area is unbounded. » Session 87: L’Hospital’s Rule » Session 88: Examples of L’Hospital’s Rule » Session 89: L’Hospital’s Rule and Rates of Growth » Session 90: Advanced Examples of L’Hospital’s Rule » Session 91: Improper Integrals » Session 92: Integral Comparison » Session 93: Indefinite Integrals and Singularities', 100, 16),
('cddb451e-73ec-50cd-ba81-17cd619c155e', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Unit 5B: Taylor Series', 'We can use limits to formally define sums of infinitely many values. Taylor Series are infinite sums defined in terms of polynomials, and provide an alternate means of describing standard functions. » Session 94: Infinite Series » Session 95: Series Comparison » Session 96: Stacking Blocks » Session 97: Power Series » Session 98: Taylor’s Series » Session 99: Taylor’s Series, Continued » Session 100: Operations on Power Series » Session 101: Conclusion', 100, 17),
('d1f076b0-4a2d-52a4-aec1-f8866af00609', '3f88f62e-7669-595c-a9aa-3c013397b933', 'Session 102: Materials for Final Exam', '« Previous Overview In this session you will: Test your knowledge by taking the final exam Exam Materials Final Exam (PDF) Solutions to Final Exam (PDF) Did this course have everything you needed to learn the subject? Are there ways we could improve it? Let us know.', 100, 18);
